  integer, parameter :: N_EXT1=261, M_EXT1=170  !RV0+RV1
  integer, parameter :: N_EXT2=348, M_EXT2=257  !RV0+RV1+RV2
  integer, parameter :: N_NEW_PER_RV=87          !New parity bits per extension

