  ! ext2_cols(MAX_ROW_WT_EXT, N_NEW_PER_RV): columns connected to each ext2 row
  ! Col 1: self-connection (new parity bit), Cols 2-6: PEG edges to base (1-174)
  integer :: ext1_cols(MAX_ROW_WT_EXT, N_NEW_PER_RV)
