  subroutine init_ldpc348_91()
  ! No-op: extension data is now static DATA statements.
  ! Kept for API compatibility with existing callers.
  end subroutine init_ldpc348_91


  subroutine encode348_91(message91, codeword348)
  ! Encode a 91-bit message into a 348-bit mother codeword.
  !
  ! First 174 bits: standard LDPC(174,91) encoding
  ! Bits 175-261: RV1 extension parity (RA accumulate)
  ! Bits 262-348: RV2 extension parity (RA accumulate)

    implicit none
    integer*1, intent(in) :: message91(K_MOTHER)
    integer*1, intent(out) :: codeword348(N_MOTHER)
    integer*1 :: cw174(N_BASE)
    integer*1 :: msgbits77(77)
    integer :: i, j, nsum

    call init_ldpc348_91()   !No-op, kept for compatibility

    ! Standard LDPC(174,91) encoding for first 174 bits
    msgbits77 = message91(1:77)
    call encode174_91(msgbits77, cw174)
    codeword348(1:N_BASE) = cw174

    ! RV1 extension parity: each bit = XOR of connected systematic bits
    do i = 1, N_NEW_PER_RV
       nsum = 0
       do j = 2, ext1_nrw(i)          !Skip first col (self = new parity bit)
          nsum = nsum + codeword348(ext1_cols(j, i))
       enddo
       codeword348(N_BASE + i) = mod(nsum, 2)
    enddo

    ! RV2 extension parity: same structure
    do i = 1, N_NEW_PER_RV
       nsum = 0
       do j = 2, ext2_nrw(i)
          nsum = nsum + codeword348(ext2_cols(j, i))
       enddo
       codeword348(N_EXT1 + i) = mod(nsum, 2)
    enddo

  end subroutine encode348_91


  subroutine puncture_rv(codeword348, rv, transmitted174)
  ! Extract 174 bits to transmit for a given redundancy version.
  !
  ! RV0: bits 1-174 (standard LDPC(174,91) codeword)
  ! RV1: 87 new parity (175-261) + 87 highest-degree systematic (1-87)
  ! RV2: 87 new parity (262-348) + 87 mixed systematic/parity bits

    implicit none
    integer*1, intent(in) :: codeword348(N_MOTHER)
    integer, intent(in) :: rv
    integer*1, intent(out) :: transmitted174(N_BASE)

    select case(rv)
    case(0)
       ! RV0: standard first 174 bits
       transmitted174 = codeword348(1:N_BASE)

    case(1)
       ! RV1: 87 new parity bits + 87 systematic bits (for chase gain)
       transmitted174(1:87) = codeword348(N_BASE+1:N_EXT1)    !New parity
       transmitted174(88:174) = codeword348(1:87)              !Systematic repeat

    case(2)
       ! RV2: 87 new parity bits + 87 systematic bits
       transmitted174(1:87) = codeword348(N_EXT1+1:N_EXT2)    !New parity
       transmitted174(88:174) = codeword348(1:87)              !Systematic repeat

    case default
       transmitted174 = 0
    end select

  end subroutine puncture_rv


  subroutine bpdecode_ext(llr_combined, ncombined, maxiterations, &
       message77, nharderror, iter)
  ! BP decoder for extended LDPC codes: LDPC(261,91) or LDPC(348,91).
  !
  ! Uses the base LDPC(174,91) Tanner graph augmented with extension rows.
  ! Falls back to standard bpdecode174_91 on the first 174 LLRs if the
  ! extended decode fails (graceful degradation).
  !
  ! Input:
  !   llr_combined(ncombined) - combined LLRs (261 for RV0+1, 348 for RV0+1+2)
  !   ncombined               - 261 or 348
  !   maxiterations           - max BP iterations
  !
  ! Output:
  !   message77(77)           - decoded message bits
  !   nharderror              - number of hard errors (-1 if failed)
  !   iter                    - iterations used

    use iso_c_binding, only: c_loc, c_size_t
    use crc
    implicit none

    integer, intent(in) :: ncombined, maxiterations
    real, intent(in) :: llr_combined(ncombined)
    integer*1, intent(out) :: message77(77)
    integer, intent(out) :: nharderror, iter

    ! Local -- base code structures
    integer, parameter :: N=174, K=91, M=83
    ! Extended Tanner graph arrays
    integer, parameter :: MAX_CHECKS = M_MOTHER      !257
    integer, parameter :: MAX_BITS = N_MOTHER         !348

    integer :: nrw(M), ncw
    integer :: Nm(7,M), Mn(3,N)
    integer :: nrw_ext(MAX_CHECKS)
    integer :: Nm_ext(7, MAX_CHECKS)
    integer, parameter :: MAX_COL_WT = 9            !Max checks per bit (3 base + 3 ext1 + 3 ext2)
    integer :: Mn_ext(MAX_COL_WT, MAX_BITS)
    integer :: ncw_ext(MAX_BITS)                      !Checks per bit (variable)

    real :: zn(MAX_BITS), tov(MAX_COL_WT,MAX_BITS), toc(7,MAX_CHECKS)
    real :: tanhtoc(7,MAX_CHECKS)
    integer*1 :: cw(MAX_BITS), decoded(K)
    integer :: synd(MAX_CHECKS)
    integer :: nrows, ncols
    integer :: i, j, kk, ibj, ichk, ncheck, ncnt, nclast, nd, nbadcrc, nsum
    real :: Tmn, y

    ! Base code parity check data (DATA statements for Mn, Nm, nrw, ncw)
    include "../ft8/ldpc_174_91_c_parity.f90"

    call init_ldpc348_91()   !No-op, kept for compatibility

    nharderror = -1
    message77 = 0

    ! Determine extended code dimensions
    if(ncombined .eq. N_EXT1) then
       nrows = M_EXT1                   !170
       ncols = N_EXT1                   !261
    else if(ncombined .eq. N_EXT2) then
       nrows = M_EXT2                   !257
       ncols = N_EXT2                   !348
    else
       ! Unknown size -- fall back to base decode
       call fallback_base_decode()
       return
    endif

    ! Build extended Tanner graph
    ! Start with base graph
    Nm_ext = 0
    Mn_ext = 0
    ncw_ext = 0
    nrw_ext = 0

    ! Copy base parity check matrix (rows 1-83)
    do j = 1, M
       nrw_ext(j) = nrw(j)
       Nm_ext(1:7, j) = Nm(1:7, j)
    enddo
    do i = 1, N
       ncw_ext(i) = ncw          !3 for base code
       Mn_ext(1:3, i) = Mn(1:3, i)
    enddo

    ! Add extension 1 rows (84-170) for bits 175-261
    if(ncols .ge. N_EXT1) then
       do i = 1, N_NEW_PER_RV
          j = M + i                    !Row index in extended graph
          nrw_ext(j) = ext1_nrw(i)
          do kk = 1, ext1_nrw(i)
             Nm_ext(kk, j) = ext1_cols(kk, i)
             ! Also update column-to-row mapping
             ibj = ext1_cols(kk, i)
             ncw_ext(ibj) = ncw_ext(ibj) + 1
             if(ncw_ext(ibj) .le. MAX_COL_WT) then
                Mn_ext(ncw_ext(ibj), ibj) = j
             endif
          enddo
       enddo
    endif

    ! Add extension 2 rows (171-257) for bits 262-348
    if(ncols .ge. N_EXT2) then
       do i = 1, N_NEW_PER_RV
          j = M_EXT1 + i              !Row index
          nrw_ext(j) = ext2_nrw(i)
          do kk = 1, ext2_nrw(i)
             Nm_ext(kk, j) = ext2_cols(kk, i)
             ibj = ext2_cols(kk, i)
             ncw_ext(ibj) = ncw_ext(ibj) + 1
             if(ncw_ext(ibj) .le. MAX_COL_WT) then
                Mn_ext(ncw_ext(ibj), ibj) = j
             endif
          enddo
       enddo
    endif

    ! BP decoding on extended graph
    toc = 0.0
    tov = 0.0
    tanhtoc = 0.0

    ! Initialize check-to-variable messages
    do j = 1, nrows
       do i = 1, nrw_ext(j)
          ibj = Nm_ext(i, j)
          if(ibj .ge. 1 .and. ibj .le. ncols) then
             toc(i, j) = llr_combined(ibj)
          endif
       enddo
    enddo

    ncnt = 0
    nclast = 0

    do iter = 0, maxiterations

       ! Update bit LLRs
       do i = 1, ncols
          zn(i) = llr_combined(i) + sum(tov(1:ncw_ext(i), i))
       enddo

       ! Syndrome check
       cw(1:ncols) = 0
       where(zn(1:ncols) .gt. 0.0) cw(1:ncols) = 1
       ncheck = 0
       do i = 1, nrows
          nsum = 0
          do kk = 1, nrw_ext(i)
             ibj = Nm_ext(kk, i)
             if(ibj .ge. 1 .and. ibj .le. ncols) nsum = nsum + cw(ibj)
          enddo
          synd(i) = mod(nsum, 2)
          if(synd(i) .ne. 0) ncheck = ncheck + 1
       enddo

       if(ncheck .eq. 0) then
          decoded = cw(1:K)
          call chkcrc14a(decoded, nbadcrc)
          nharderror = count((2*cw(1:ncols)-1) * llr_combined(1:ncols) .lt. 0.0)
          if(nbadcrc .eq. 0) then
             message77 = decoded(1:77)
             return
          endif
       endif

       ! Early stopping
       if(iter .gt. 0) then
          nd = ncheck - nclast
          if(nd .lt. 0) then
             ncnt = 0
          else
             ncnt = ncnt + 1
          endif
          if(ncnt .ge. 5 .and. iter .ge. 10 .and. ncheck .gt. 15) then
             nharderror = -1
             return
          endif
       endif
       nclast = ncheck

       ! Bit-to-check messages
       do j = 1, nrows
          do i = 1, nrw_ext(j)
             ibj = Nm_ext(i, j)
             if(ibj .lt. 1 .or. ibj .gt. ncols) cycle
             toc(i, j) = zn(ibj)
             do kk = 1, ncw_ext(ibj)
                if(Mn_ext(kk, ibj) .eq. j) then
                   toc(i, j) = toc(i, j) - tov(kk, ibj)
                endif
             enddo
          enddo
       enddo

       ! Check-to-bit messages
       do i = 1, nrows
          do kk = 1, nrw_ext(i)
             tanhtoc(kk, i) = tanh(-toc(kk, i) / 2.0)
          enddo
       enddo

       do j = 1, ncols
          do i = 1, ncw_ext(j)
             ichk = Mn_ext(i, j)
             if(ichk .lt. 1 .or. ichk .gt. nrows) cycle
             Tmn = product(tanhtoc(1:nrw_ext(ichk), ichk), &
                  mask=Nm_ext(1:nrw_ext(ichk), ichk) .ne. j)
             call platanh(-Tmn, y)
             tov(i, j) = 2.0 * y
          enddo
       enddo

    enddo  !iter

    ! BP failed -- try fallback on base code LLRs
    call fallback_base_decode()
    return

  contains

    subroutine fallback_base_decode()
      ! Fall back to standard LDPC(174,91) BP decode using first 174 LLRs
      integer*1 :: apmask_zero(N_BASE)
      integer*1 :: cw_base(N_BASE)
      integer :: ncheck_base

      apmask_zero = 0
      call bpdecode174_91(llr_combined(1:N_BASE), apmask_zero, maxiterations, &
           message77, cw_base, nharderror, iter, ncheck_base)
    end subroutine fallback_base_decode

  end subroutine bpdecode_ext


  subroutine bpdecode_ext_soft(llr_combined, ncombined, maxiterations, &
       message77, zn_out, nharderror, ncheck_out, iter)
  ! Soft-output sibling of bpdecode_ext: identical BP on the extended Tanner
  ! graph, but also returns the per-bit a-posteriori belief zn_out(1:ncombined)
  ! and the final unsatisfied-check count ncheck_out, so a joint-turbo HARQ
  ! caller can form the LDPC extrinsic (zn_out - channel_llr) to feed back into
  ! the per-frame BCJR. Supports ncombined = N_EXT1 (261) or N_EXT2 (348).
    use crc
    implicit none
    integer, intent(in)  :: ncombined, maxiterations
    real,    intent(in)  :: llr_combined(ncombined)
    integer*1, intent(out) :: message77(77)
    real,    intent(out) :: zn_out(ncombined)
    integer, intent(out) :: nharderror, ncheck_out, iter

    integer, parameter :: N=174, K=91, M=83
    integer, parameter :: MAX_CHECKS = M_MOTHER
    integer, parameter :: MAX_BITS   = N_MOTHER
    integer, parameter :: MAX_COL_WT = 9
    integer :: nrw(M), ncw
    integer :: Nm(7,M), Mn(3,N)
    integer :: nrw_ext(MAX_CHECKS), Nm_ext(7,MAX_CHECKS)
    integer :: Mn_ext(MAX_COL_WT,MAX_BITS), ncw_ext(MAX_BITS)
    real    :: zn(MAX_BITS), tov(MAX_COL_WT,MAX_BITS), toc(7,MAX_CHECKS)
    real    :: tanhtoc(7,MAX_CHECKS)
    integer*1 :: cw(MAX_BITS), decoded(K)
    integer :: synd(MAX_CHECKS)
    integer :: nrows, ncols
    integer :: i, j, kk, ibj, ichk, ncheck, ncnt, nclast, nd, nbadcrc, nsum
    real    :: Tmn, y

    include "../ft8/ldpc_174_91_c_parity.f90"

    call init_ldpc348_91()
    nharderror = -1; message77 = 0; ncheck_out = 99; zn_out = 0.0

    if(ncombined .eq. N_EXT1) then
       nrows = M_EXT1; ncols = N_EXT1
    else if(ncombined .eq. N_EXT2) then
       nrows = M_EXT2; ncols = N_EXT2
    else
       return                     !only extended sizes supported
    endif

    ! Build extended Tanner graph (identical to bpdecode_ext)
    Nm_ext = 0; Mn_ext = 0; ncw_ext = 0; nrw_ext = 0
    do j = 1, M
       nrw_ext(j) = nrw(j); Nm_ext(1:7,j) = Nm(1:7,j)
    enddo
    do i = 1, N
       ncw_ext(i) = ncw; Mn_ext(1:3,i) = Mn(1:3,i)
    enddo
    if(ncols .ge. N_EXT1) then
       do i = 1, N_NEW_PER_RV
          j = M + i; nrw_ext(j) = ext1_nrw(i)
          do kk = 1, ext1_nrw(i)
             Nm_ext(kk,j) = ext1_cols(kk,i); ibj = ext1_cols(kk,i)
             ncw_ext(ibj) = ncw_ext(ibj) + 1
             if(ncw_ext(ibj) .le. MAX_COL_WT) Mn_ext(ncw_ext(ibj),ibj) = j
          enddo
       enddo
    endif
    if(ncols .ge. N_EXT2) then
       do i = 1, N_NEW_PER_RV
          j = M_EXT1 + i; nrw_ext(j) = ext2_nrw(i)
          do kk = 1, ext2_nrw(i)
             Nm_ext(kk,j) = ext2_cols(kk,i); ibj = ext2_cols(kk,i)
             ncw_ext(ibj) = ncw_ext(ibj) + 1
             if(ncw_ext(ibj) .le. MAX_COL_WT) Mn_ext(ncw_ext(ibj),ibj) = j
          enddo
       enddo
    endif

    toc = 0.0; tov = 0.0; tanhtoc = 0.0
    do j = 1, nrows
       do i = 1, nrw_ext(j)
          ibj = Nm_ext(i,j)
          if(ibj .ge. 1 .and. ibj .le. ncols) toc(i,j) = llr_combined(ibj)
       enddo
    enddo
    ncnt = 0; nclast = 0

    do iter = 0, maxiterations
       do i = 1, ncols
          zn(i) = llr_combined(i) + sum(tov(1:ncw_ext(i),i))
       enddo
       cw(1:ncols) = 0
       where(zn(1:ncols) .gt. 0.0) cw(1:ncols) = 1
       ncheck = 0
       do i = 1, nrows
          nsum = 0
          do kk = 1, nrw_ext(i)
             ibj = Nm_ext(kk,i)
             if(ibj .ge. 1 .and. ibj .le. ncols) nsum = nsum + cw(ibj)
          enddo
          synd(i) = mod(nsum,2)
          if(synd(i) .ne. 0) ncheck = ncheck + 1
       enddo
       ncheck_out = ncheck
       zn_out(1:ncols) = zn(1:ncols)
       if(ncheck .eq. 0) then
          decoded = cw(1:K)
          call chkcrc14a(decoded, nbadcrc)
          nharderror = count((2*cw(1:ncols)-1)*llr_combined(1:ncols) .lt. 0.0)
          if(nbadcrc .eq. 0) then
             message77 = decoded(1:77)
             return
          endif
       endif
       if(iter .gt. 0) then
          nd = ncheck - nclast
          if(nd .lt. 0) then; ncnt = 0; else; ncnt = ncnt + 1; endif
          if(ncnt .ge. 5 .and. iter .ge. 10 .and. ncheck .gt. 15) then
             nharderror = -1
             return
          endif
       endif
       nclast = ncheck
       do j = 1, nrows
          do i = 1, nrw_ext(j)
             ibj = Nm_ext(i,j)
             if(ibj .lt. 1 .or. ibj .gt. ncols) cycle
             toc(i,j) = zn(ibj)
             do kk = 1, ncw_ext(ibj)
                if(Mn_ext(kk,ibj) .eq. j) toc(i,j) = toc(i,j) - tov(kk,ibj)
             enddo
          enddo
       enddo
       do i = 1, nrows
          do kk = 1, nrw_ext(i)
             tanhtoc(kk,i) = tanh(-toc(kk,i)/2.0)
          enddo
       enddo
       do j = 1, ncols
          do i = 1, ncw_ext(j)
             ichk = Mn_ext(i,j)
             if(ichk .lt. 1 .or. ichk .gt. nrows) cycle
             Tmn = product(tanhtoc(1:nrw_ext(ichk),ichk), &
                  mask=Nm_ext(1:nrw_ext(ichk),ichk) .ne. j)
             call platanh(-Tmn, y)
             tov(i,j) = 2.0*y
          enddo
       enddo
    enddo
    nharderror = -1
    return
  end subroutine bpdecode_ext_soft

end module ldpc348_91_mod
